import { AsyncPipe } from '@angular/common';
import { Component, inject } from '@angular/core';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { map, tap } from 'rxjs';
import { CookieConsentService } from '../../services/cookie-consent.service';
import { LanguageService } from '../../services/language.service';
import { SeoService } from '../../services/seo.service';
import { SiteService } from '../../services/site.service';

type LegalDocument = 'privacy' | 'cookies';

@Component({
  selector: 'app-legal-page',
  standalone: true,
  imports: [AsyncPipe, RouterLink],
  templateUrl: './legal.page.html',
  styleUrl: './legal.page.sass'
})
export class LegalPage {
  private readonly route = inject(ActivatedRoute);
  private readonly siteService = inject(SiteService);
  private readonly languageService = inject(LanguageService);
  private readonly seoService = inject(SeoService);
  private readonly cookieConsentService = inject(CookieConsentService);

  protected readonly vm$ = this.siteService.getSiteConfig().pipe(
    map((siteConfig) => {
      const language = this.languageService.getRouteLanguage(this.route.snapshot);
      const document = (this.route.snapshot.data['legalDocument'] as LegalDocument) || 'privacy';

      return {
        siteConfig,
        language,
        document,
        lastUpdated: this.formatDate(siteConfig.legal.lastUpdated, language)
      };
    }),
    tap(({ siteConfig, language, document }) => {
      this.seoService.applyLocalizedAlternates(
        siteConfig.domain,
        this.route.snapshot,
        undefined,
        siteConfig.defaultLanguage
      );

      const isPrivacy = document === 'privacy';
      const title = isPrivacy ? 'Privacy Policy' : 'Cookie Policy';
      const description = language === 'it'
        ? `${title} del sito ufficiale di ${siteConfig.artistName}.`
        : `${title} for the official website of ${siteConfig.artistName}.`;

      this.seoService.applyPageMetadata({
        title: `${title} | ${siteConfig.artistName}`,
        description,
        url: `${siteConfig.domain}${this.languageService.buildLocalizedPath(language, isPrivacy ? 'privacy' : 'cookie-policy')}`,
        siteName: siteConfig.artistName,
        language
      });
    })
  );

  protected openCookiePreferences(): void {
    this.cookieConsentService.requestPreferences();
  }

  private formatDate(value: string, language: 'it' | 'en'): string {
    const date = new Date(`${value}T00:00:00`);
    if (Number.isNaN(date.getTime())) {
      return value;
    }

    return new Intl.DateTimeFormat(language === 'it' ? 'it-IT' : 'en-GB', {
      day: 'numeric',
      month: 'long',
      year: 'numeric'
    }).format(date);
  }
}
